var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......그렇습니까.","JPN":"……そうでしたか。","ENG":"I see.","TWN":"……是嗎。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"결국 리타와 대시는 귀환에 실패했군요.","JPN":"結局リタとダッシュは帰還に失敗したのですね。","ENG":"So Rita and Dash failed to return after all.","TWN":"最後，麗塔和黛西還是沒有回來現世嗎。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"이런 소식을 전해 드려 유감입니다.","JPN":"このような知らせで残念です。","ENG":"I'm sorry you had to hear this.","TWN":"很遺憾，通知您這樣的消息。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그녀들에게서 채취한 이터니움은 폐기 판정을 받고 관리국에 회수된 상태입니다.","JPN":"彼女たちから採取したエタニウムは廃棄判定を受け、管理局に回収されています。","ENG":"The Eternium extracted from them has been marked for disposal and collected by the Administration.","TWN":"從她們身上採集的永恆之金因為不能使用只能廢棄，所以被管理局回收了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"제가 드릴 수 있는 건...... 미니스트라와의 교전 후에 회수한 당신의 기억 회로뿐이겠군요.","JPN":"こちらから差し上げられるものは、ミニストラとの交戦後に回収したあなたの記憶回路のみです。","ENG":"All I can give you... is your memory unit recovered after the engagement with Ministra.","TWN":"我能交給您的……只有在跟潼恩交戰後所回收的與您有關的記憶迴路。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"괜찮습니다.","JPN":"心配無用です。","ENG":"It's okay.","TWN":"沒關係。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"저는 인간이 아닌 기계이므로, 유품을 통해 휘발된 감정을 재생하는 방법은 모릅니다.","JPN":"私は人間ではなく機械なので、遺品を通じて発生した感情を再生する方法はわかりません。","ENG":"I am a machine. Unlike humans, I do not know how to reminisce about others, based only on their belongings.","TWN":"我是機器不是人類，不懂如何透過遺物重新喚起失去的感情。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타가 쓰던 책상도, 대시가 쓰던 가계부도 현재 모두 처분한 상태입니다.","JPN":"リタが使っていたデスクも、ダッシュが書いていた家計簿もすべて処分しています。","ENG":"I've already disposed of Rita's desk and Dash's ledger.","TWN":"麗塔用過的書桌，黛西用過的帳簿現在都已經處理掉了。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......그렇군요.","JPN":"……そうでしたか。","ENG":"I see...","TWN":"……原來如此。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만, 그럼 어째서 그녀들에게서 나온 이터니움을 구매하겠다고 하신 거죠?","JPN":"では、どうして彼女たちから出てきたエタニウムを買うとおっしゃったのですか？","ENG":"Then why did you offer to purchase the Eternium from them?","TWN":"但是，您為什麼還說要購買她們的永恆之金呢？"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"책임을 지기 위해서입니다.","JPN":"責任を取るためです。","ENG":"To bear responsibility.","TWN":"為了負責。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"계약서에 따르면 직원들의 안전 역시 대표인 저의 책임입니다.","JPN":"契約書によれば、職員たちの安全も代表である私の責任です。","ENG":"As their employer, I have a contractual obligation to ensure their safety.","TWN":"按照合約，職員的安全就是身為老闆的我所該背負的責任。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"저는 그 책임을 완수하지 못했습니다.","JPN":"私はその責任を果たすことができませんでした。","ENG":"And I failed to honor that obligation.","TWN":"我沒盡到那個責任。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그렇다면 최소한 뒷일은 잘 마무리해야겠죠.","JPN":"ならば少なくとも、後始末だけはしっかりやらなければならないでしょう。","ENG":"The least I can do is follow suit with due diligence.","TWN":"所以，至少要好好的處理後事。"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CLUB1","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"두 사람이 오기 전까지, 호라이즌 파이낸스는 인상적인 일처리로 유명했습니다, 휴먼.","JPN":"二人が来る前まで、ホライズン・ファイナンスは印象深い仕事ぶりで有名でした、ヒューマン。","ENG":"Before those two joined the company, Horizon Finance was notorious for its... intense business operations.","TWN":"在她們兩個來到我這之前，地平線金融可是以令人印象深刻的辦事方式而聞名的，人類。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"필요하다면 수금 과정에서 과격한 수단을 동원하기도 했죠.","JPN":"必要ならば集金の過程で過激な手段を伴うこともありました。","ENG":"I didn't hesitate to resort to more aggressive measures to ensure timely collection.","TWN":"在收款過程中，必要時也會動用一些特殊手段。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"하지만 그러기 위해서는 안정적인 동력원이 필요했습니다.","JPN":"しかし、そのためには安定した動力源が必要でした。","ENG":"But in order to do so, I needed a stable source of power.","TWN":"但為此需要穩定的動力源。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"당신의 회사에서 이터니움을 구매하려던 건 단지 동력원을 확보하기 위해서였습니다.","JPN":"あなたの会社からエタニウムを購入しようとしたのは、ただ動力源を確保するためでした。","ENG":"The sole reason I sought to purchase the Eternium from you was to secure such a power source.","TWN":"想從您的公司購買永恆之金就是為了確保動力源。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 제게 제시한 가격은 시세보다 훨씬 높은 가격이었죠.","JPN":"しかし、私に提示された価格は相場よりはるかに高い価格でした。","ENG":"But the price you offered was well above the market price.","TWN":"但您給出的價格比市價高太多了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기계답지 않게 불합리한 결정이라고 생각되네요.","JPN":"機械らしくない、不合理な決定だと思われますね。","ENG":"I didn't realize a machine could make such an irrational decision.","TWN":"我覺得這不符合身為機器人該有的思維。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"당신은 냉정해 보이는 사업가로군요.","JPN":"あなたは冷静な事業家のようですね。","ENG":"You seem like an astute businesswoman.","TWN":"沒想到您是個冷靜的企業家。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그렇다면 묻겠습니다. 당신은 항상 합리적으로 행동합니까.","JPN":"それではお聞きます。あなたは常に合理的に行動しますか。","ENG":"So let me ask you this. Are your actions always driven by reason?","TWN":"既然這樣，我想問妳一個問題。您對待任何問題總是能如此保持冷靜嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그렇지는...... 않죠.","JPN":"そう……ではありませんね。","ENG":"Well... I guess not.","TWN":"也……不是。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네, 무슨 말인지 이해했습니다.","JPN":"はい、どういう意味なのか理解しました。","ENG":"Very well. I get what you're trying to say.","TWN":"好，我理解了。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"하지만 귀사와의 첫 거래가 이런 불완전한 형태로 끝난 것은 무척 아쉽군요.","JPN":"しかし、御社との初めての取引がこのような不完全な形で終わったことは非常に残念です。","ENG":"I'm just disappointed our first deal has to come to such an incomplete end.","TWN":"但是，與貴公司的首次交易並不完美，實在令人遺憾。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"혹시 저희의 도움이 필요한 일이 있으시면 말씀해 주시죠.","JPN":"もし弊社の助けが必要なことがあれば、いつでもおっしゃってください。","ENG":"Do let us know if you require our service in any other way.","TWN":"如果還有什麼需要我們幫忙，請儘管開口。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"거래처와의 신의를 지키기 위해서니, 사장님께서도 매우 긍정적으로 생각하실 겁니다.","JPN":"取引先との信義のためですから、社長もとても前向きに考えていると思います。","ENG":"I'm sure our President would be supportive of our efforts to preserve our client's confidence in us.","TWN":"為了維護與客戶之間的信任，我們老闆也會積極配合的。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......윌버란 인간의 행방을 알게 되면 제게 말씀해 주십시오.","JPN":"……ウィルバーという人間の居場所がわかった時はお知らせください。","ENG":"If you ever come across the whereabouts of a human named Wilbur, please let me know.","TWN":"那……請貴公司如果知道韋爾伯那個人類的行蹤，請告知我。"},"stage":{"bg":"SS_SHADOW_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"이면세계에서 돌아온 후 행방이 묘연한 상태입니다.","JPN":"裏世界から帰ってきた後、行方がわからない状態です。","ENG":"He went off the grid after his return from the Counterside.","TWN":"從異界回來後，就行蹤不明了。"},"stage":{"bg":"SS_SHADOW_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그거라면 걱정 마시죠.","JPN":"それならご心配なく。","ENG":"You can count on us.","TWN":"這點不用擔心。"},"stage":{"bg":"SS_SHADOW_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"심연 밑바닥에 숨어 있더라도, 반드시 찾아드리겠습니다.","JPN":"深淵の底に隠れていたとしても、必ず探し出して差し上げます。","ENG":"We'll find him no matter what, even if he's hiding in the deepest reaches of the abyss.","TWN":"就算他躲在地底深淵，也一定會為您找到的。"},"stage":{"bg":"SS_SHADOW_04","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};